import{_ as a,o as s,c as i,ai as r,uc as o,ud as n,ue as t,uf as l,ug as d,uh as p}from"./chunks/framework.DIUhWiTt.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notas/PortSwigger/5.Authentication vulnerabilities/3.Username enumeration via response timing/3.Username enumeration via response timing.md","filePath":"notas/PortSwigger/5.Authentication vulnerabilities/3.Username enumeration via response timing/3.Username enumeration via response timing.md"}'),c={name:"notas/PortSwigger/5.Authentication vulnerabilities/3.Username enumeration via response timing/3.Username enumeration via response timing.md"};function u(h,e,m,g,k,b){return s(),i("div",null,[...e[0]||(e[0]=[r('<h2 id="bypass-de-ip-block-usando-x-forwarded-for" tabindex="-1">Bypass de IP Block usando <code>X-Forwarded-For</code> <a class="header-anchor" href="#bypass-de-ip-block-usando-x-forwarded-for" aria-label="Permalink to “Bypass de IP Block usando X-Forwarded-For”">​</a></h2><p>Algunas aplicaciones web implementan <strong>control de acceso basado en IP</strong> (ej., permitir solo tráfico desde ciertas IP o bloquear direcciones sospechosas).<br> Para identificar al cliente, el servidor normalmente revisa:</p><ul><li><strong><code>REMOTE_ADDR</code></strong> → IP real que hace la conexión.</li><li><strong>Cabeceras HTTP opcionales</strong> como <code>X-Forwarded-For</code> o <code>X-Real-IP</code>.</li></ul><p><code>X-Forwarded-For</code> (XFF) es un header estándar que se utiliza para indicar la IP original del cliente cuando la petición pasa por un <strong>proxy o balanceador</strong>. Ejemplo:</p><p>Esto le dice al backend: <em>“la IP real del cliente es 203.0.113.25”</em>.</p><h3 id="el-problema" tabindex="-1">El problema <a class="header-anchor" href="#el-problema" aria-label="Permalink to “El problema”">​</a></h3><p>Muchos desarrolladores confían <strong>ciegamente</strong> en <code>X-Forwarded-For</code> sin validar:</p><ul><li>¿Proviene realmente de un proxy interno de confianza?</li><li>¿Es un valor legítimo?</li></ul><p>Esto permite a un atacante <strong>inyectar su propia IP en la cabecera y engañar al sistema</strong>.</p><h3 id="ejemplo-de-bypass" tabindex="-1">Ejemplo de bypass <a class="header-anchor" href="#ejemplo-de-bypass" aria-label="Permalink to “Ejemplo de bypass”">​</a></h3><p>Supón que una aplicación bloquea todo tráfico excepto desde <code>192.168.1.10</code>.<br> El atacante agrega:</p><p>Si el backend usa <code>X-Forwarded-For</code> para la validación, <strong>cree que eres la IP whitelisted</strong>.</p><h3 id="por-que-funciona" tabindex="-1">Por qué funciona <a class="header-anchor" href="#por-que-funciona" aria-label="Permalink to “Por qué funciona”">​</a></h3><ul><li>Las cabeceras HTTP son controladas por el cliente, a menos que el servidor las filtre.</li><li>Muchos frameworks (<code>PHP</code>, <code>ASP.NET</code>, <code>Java</code>) asignan directamente <code>X-Forwarded-For</code> a la IP &quot;real&quot; si está presente.</li></ul><h2 id="lab" tabindex="-1">LAB <a class="header-anchor" href="#lab" aria-label="Permalink to “LAB”">​</a></h2><p><img src="'+o+'" alt="20250803173206.png"></p><p>Interceptando las solicitudes desde el burpsuite, observamos que en cierto numero de logins inválidos, el servidor ya no nos deja enviar otra.</p><p><img src="'+n+'" alt="20250803180953.png"></p><p>Por lo que tenemos que bypasear esta restricción de bloqueo de IP.</p><ul><li><a href="https://rajanagori.medium.com/bypass-ip-block-with-the-x-forwarded-for-header-8c1dbd89ae58" target="_blank" rel="noreferrer">https://rajanagori.medium.com/bypass-ip-block-with-the-x-forwarded-for-header-8c1dbd89ae58</a></li></ul><p>En el anterior articulo encontraremos que haciendo uso o cambiando el valor del header <code>X-Forwarded-For: 1</code> e iterando valores de este podemos enviar solicitudes sin que el servidor nos bloquee</p><p><img src="'+t+'" alt="20250803181018.png"></p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Forwarded</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">For: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre></div><p>Entendiendo esto, usaremos un ataque de tipo <code>Pitchfork attack</code> el cual nos permitira enviar dos listas, una para el header <code>X-Forwarded-For:</code> y otra para el <code>username</code></p><p><img src="'+l+'" alt="20250803181720.png"></p><p>Luego de espera un tiempo, podemos ver que tenemos una solicitud que tiene un tiempo de respuesta mayar en comparación a las otras.</p><p><img src="'+d+'" alt="20250803181949.png"></p><p>Entonces el usuario es:</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">albuquerque</span></span></code></pre></div><p>Ahora, teniendo usuario intentaremos hacer brute force para encontrar la password.</p><p><img src="'+p+'" alt="20250803182239.png"></p><p>Luego de lanzar la solicitudes vemos que tenemos la contraseña, para este caso yo use <code>Grep - Extract</code> para filtrar cual es la solicitud que no tenia <code>Invalid Username or password</code>. Asi tendríamos la contraseña <code>dragon</code></p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">username</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">albuquerque</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">password</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dragon</span></span></code></pre></div>',33)])])}const y=a(c,[["render",u]]);export{f as __pageData,y as default};
